import * as React from 'react';
import { IWebPartContext } from '@microsoft/sp-webpart-base';
import { PrimaryButton } from '@fluentui/react';
import { sp } from '@pnp/sp';
import '@pnp/sp/webs';
import '@pnp/sp/site-users';
import * as XLSX from 'xlsx-js-style';

export default class CredentialToExcelWebPart extends React.Component<{ context: IWebPartContext }, { status: string }> {
  constructor(props: { context: IWebPartContext }) {
    super(props);
    this.state = { status: 'Ready' };
    sp.setup({ spfxContext: this.props.context });
  }

  private async fetchUserCredentials() {
    try {
      const currentUser = await sp.web.currentUser();
      const userData = {
        Name: currentUser.Title,
        Email: currentUser.Email
      };

      // Update Excel file in SharePoint
      await this.updateExcelFile(userData);
      this.setState({ status: 'Credentials saved successfully!' });
    } catch (error) {
      this.setState({ status: `Error: ${error.message}` });
    }
  }

  private async updateExcelFile(userData: { Name: string, Email: string }) {
    const fileName = 'UserCredentials.xlsx';
    const fileServerRelativeUrl = `/sites/YourSite/Documents/${fileName}`;
    const serverRelativeUrl = `/sites/YourSite/Documents`;

    // Check if file exists
    try {
      await sp.web.getFileByServerRelativePath(fileServerRelativeUrl).getContent();
      // File exists - update it
      const workbook = XLSX.read(await sp.web.getFileByServerRelativePath(fileServerRelativeUrl).getContent(), { type: 'buffer' });
      const worksheet = workbook.Sheets[workbook.SheetNames[0]];
      const data = XLSX.utils.sheet_to_json(worksheet);
      data.push(userData);
      const newWorksheet = XLSX.utils.json_to_sheet(data);
      const newWorkbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(newWorkbook, newWorksheet, 'Users');
      const excelBuffer = XLSX.write(newWorkbook, { type: 'buffer', bookType: 'xlsx' });
      await sp.web.getFolderByServerRelativePath(serverRelativeUrl).files.getByName(fileName).setContent(excelBuffer);
    } catch (error) {
      // File doesn't exist - create new one
      const worksheet = XLSX.utils.json_to_sheet([userData]);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, 'Users');
      const excelBuffer = XLSX.write(workbook, { type: 'buffer', bookType: 'xlsx' });
      await sp.web.getFolderByServerRelativePath(serverRelativeUrl).files.add(fileName, excelBuffer, true);
    }
  }

  public render() {
    return (
      <div>
        <PrimaryButton 
          text="Save My Credentials to Excel" 
          onClick={() => this.fetchUserCredentials()}
        />
        <p>{this.state.status}</p>
      </div>
    );
  }
}
This example uses the PnPjs library for SharePoint operations and the xlsx-js-style library for Excel file manipulation.
